external_knowledge:
- A higher win ratio indicates better performance; 
- A lower average FIFA ranking indicates a stronger team; 
- FIFA world rankings are a way to compare the relative strengths of national soccer teams.

sql:
SELECT MAX(attendance) AS highest_attendance, match_date
FROM matches
WHERE attendance = (SELECT MAX(attendance) FROM matches);

SELECT team_id, MAX(rank) AS highest_rank
FROM team_rankings
GROUP BY team_id;
